def calculate_fibonacci(n):
    """Return the nth Fibonacci number using memoization."""
    memo = {0: 0, 1: 1}
    def fib(k):
        if k not in memo:
            memo[k] = fib(k - 1) + fib(k - 2)
        return memo[k]
    return fib(n)

